def mod_inverse(a, m):
    """
    Hesaplar a'nın m'ye göre modüler çarpımsal tersini.
    Yalnızca a ve m aralarında asal ise tersi mevcuttur.
    """
    def extended_gcd(a, b):
        if a == 0:
            return (b, 0, 1)
        gcd, x1, y1 = extended_gcd(b % a, a)
        x = y1 - (b // a) * x1
        y = x1
        return (gcd, x, y)

    gcd, x, y = extended_gcd(a, m)

    if gcd != 1:
        raise ValueError(f"{a} ve {m} aralarında asal değil, modüler tersi mevcut değil.")
    else:
        return (x % m + m) % m
